import { debounce } from 'lodash-es';
import {
  type Dispatch,
  type SetStateAction,
  type JSX,
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { useIntl } from 'react-intl';

import * as styles from './DataTableVisibilityFilterControls.sty.js';
import { Checkbox } from '../../../../../forms/checkbox/Checkbox.js';
import { SearchInput } from '../../../../../forms/search-input/SearchInput.js';
import { Flex } from '../../../../../layouts/flex/Flex.js';
import { dataTableMessages } from '../../../messages.js';

/** Debounce time (ms) for search input in column settings modal. */
const SEARCH_DEBOUNCE_TIME_MS = 300;

interface DataTableVisibilityFilterControlsProps {
  /** Updates the current value of the filter. */
  setActiveFilterValue: Dispatch<SetStateAction<string>>;
  /** Determines whether all columns are currently visible. */
  showHideAllState: boolean | 'indeterminate';
  /** Callback that is called when the visibility of all columns changes. */
  onShowHideAllChange: () => void;
  /** Determines whether to show the show/hide all columns checkbox. */
  showVisibilityControl: boolean;
  /** Determines whether to show the search input for filtering columns. */
  showFilterControl: boolean;
}

/**
 * Content of the area above the columns list in the ColumnSettingsModal.
 * - a checkbox indicating whether all columns are visible and
 * - a search input for filtering the listed columns in the column settings modal. Filtering is debounced with 300ms.
 * @internal
 */
export const DataTableVisibilityFilterControls = (
  props: DataTableVisibilityFilterControlsProps,
): JSX.Element | null => {
  const {
    setActiveFilterValue,
    showHideAllState,
    onShowHideAllChange,
    showVisibilityControl,
    showFilterControl,
  } = props;

  const intl = useIntl();
  const [filterValue, setFilterValue] = useState('');

  const debouncedUpdateRef = useRef(
    debounce((value: string, setter: Dispatch<SetStateAction<string>>) => {
      setter(value);
    }, SEARCH_DEBOUNCE_TIME_MS),
  );

  const onChange = useCallback(
    (value: string) => {
      setFilterValue(value);
      debouncedUpdateRef.current(value, setActiveFilterValue);
    },
    [setActiveFilterValue],
  );

  useEffect(() => {
    const debouncedUpdate = debouncedUpdateRef.current;
    return () => {
      debouncedUpdate.cancel();
    };
  }, []);

  if (!showFilterControl && !showVisibilityControl) {
    return null;
  }

  const dataDtProperties = `state:${
    showHideAllState === true ? 'hide' : 'show'
  }`;

  return (
    <Flex
      justifyContent="space-between"
      alignItems="center"
      className={styles.filterControls}
    >
      {showVisibilityControl && (
        <Checkbox
          value={showHideAllState}
          onChange={onShowHideAllChange}
          className={styles.showHideAll}
          data-dt-name="ColumnSettingsShowHideAll"
          data-dt-properties={dataDtProperties}
        >
          {intl.formatMessage(dataTableMessages.showHideAll)}
        </Checkbox>
      )}
      {showFilterControl && (
        <SearchInput
          placeholder={intl.formatMessage(
            dataTableMessages.searchBarPlaceholder,
          )}
          className={styles.searchInput}
          onChange={onChange}
          value={filterValue}
          data-dt-name="ColumnSettingsFilter"
        />
      )}
    </Flex>
  );
};
